const row = $input.first().json;

const context = typeof row.context === 'string'
  ? JSON.parse(row.context)
  : (row.context || []);

const analysis = typeof row.analysis === 'string'
  ? JSON.parse(row.analysis)
  : row.analysis;

const transcript = context
  .map((m) => `${m.role === 'user' ? 'Сотрудник' : 'Наставник'}: ${m.text}`)
  .join('\n');

const errors = (analysis?.errors || [])
  .map((e) => `${e.code}: ${e.description}`)
  .join('; ') || 'нет';

return [{
  json: {
    session_id: row.session_id,
    dialog_id: row.dialog_id,
    employee_id: row.employee_id,
    session_transcript: transcript,
    analysis_summary: errors,
    top_error_code: (analysis?.errors || [])[0]?.code || 'GENERAL',
    ollama_body: {
      model: 'llama3.2:1b',
      stream: false,
      options: { temperature: 0.2, num_predict: 120 },
      messages: [
        {
          role: 'system',
          content: 'Сожми итог тренировки в 2–3 bullet points на русском. Фокус: ошибка, прогресс, что повторить на смене.',
        },
        {
          role: 'user',
          content: `Диалог тренировки:\n${transcript}\n\nИсходный analysis:\n${errors}`,
        },
      ],
    },
  },
}];

const prev = $('Build Summary').first().json;
const raw = $input.first().json?.message?.content || '';

let summary = raw.trim();
if (!summary) {
  summary = `• Отработана ошибка: ${prev.top_error_code}\n• Тренировка завершена`;
}
if (summary.length > 1500) summary = summary.slice(0, 1500) + '…';

return [{
  json: {
    employee_id: prev.employee_id,
    dialog_id: prev.dialog_id,
    error_code: prev.top_error_code,
    coaching_notes: summary,
    notes_escaped: summary.replace(/'/g, "''"),
  },
}];
